mapper.select:
SELECT am.id, am.name, am.description, am.question_bank_id AS questionBankId, amtm.textbook_id AS textbookId, amtm.chapter_id AS textbookCatalogId, am.status, am.creator, am.add_datetime AS addDatetime, am.operator, am.operation_datetime AS operationDatetime, (SELECT name FROM teaching_question_bank WHERE id = am.question_bank_id LIMIT 1) AS questionBankName, (SELECT textbook_name FROM textbook WHERE id = amtm.textbook_id LIMIT 1) AS textbookName, (SELECT catalog_name FROM textbook_catalog WHERE id = amtm.chapter_id LIMIT 1) AS textbookCatalogName, (SELECT nickname FROM sys_tbuser WHERE id = am.creator LIMIT 1) AS creatorName, (SELECT nickname FROM sys_tbuser WHERE id = am.operator LIMIT 1) AS operatorName, (SELECT COUNT(*) FROM application_materials_mapping WHERE application_material_id = am.id) AS teachingMaterialsCount FROM application_materials am LEFT JOIN application_materials_textbook_mapping amtm ON am.id = amtm.application_material_id
AND am.name LIKE '%' || #{param.name} || '%'
AND am.question_bank_id = #{param.questionBankId}
AND am.status = #{param.status}
AND am.creator = #{param.creator}
AND amtm.textbook_id = #{param.textbookId}
AND amtm.chapter_id = #{param.textbookCatalogId}
ORDER BY am.add_datetime
ASC DESC
